import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

const ALLOWED_METHODS = "GET, OPTIONS";
const ALLOWED_HEADERS = "Content-Type, Authorization";

const buildAllowedOrigin = () => {
  const runId = process.env.ZEALT_RUN_ID;
  if (!runId) {
    return null;
  }

  return `https://example-${runId}.com`;
};

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
) {
  const origin = request.headers.get("origin");
  const allowedOrigin = buildAllowedOrigin();
  const isAllowed = !!allowedOrigin && origin === allowedOrigin;

  if (isAllowed) {
    context.addResponseSendingHook((response) => {
      const headers = new Headers(response.headers);
      headers.set("Access-Control-Allow-Origin", allowedOrigin);
      headers.set("Access-Control-Allow-Methods", ALLOWED_METHODS);
      headers.set("Access-Control-Allow-Headers", ALLOWED_HEADERS);
      headers.append("Vary", "Origin");

      return new Response(response.body, {
        status: response.status,
        statusText: response.statusText,
        headers,
      });
    });
  }

  if (request.method === "OPTIONS") {
    const headers = new Headers();
    if (isAllowed && allowedOrigin) {
      headers.set("Access-Control-Allow-Origin", allowedOrigin);
      headers.set("Access-Control-Allow-Methods", ALLOWED_METHODS);
      headers.set("Access-Control-Allow-Headers", ALLOWED_HEADERS);
      headers.append("Vary", "Origin");
    }

    return new Response(null, { status: 204, headers });
  }

  return request;
}

